SELECT SUM(loans.sanctioned_amount) AS total_sanctioned_amount
FROM loans
WHERE collateral_required = 1;

SELECT borrowers.borrower_name, borrowers.industry, borrowers.annual_revenue, credit_scores.credit_score
FROM borrowers
INNER JOIN credit_scores ON borrowers.borrower_id = credit_scores.borrower_id;

SELECT b.borrower_name, b.contact_email, b.phone_number
FROM borrowers b
JOIN loan_applications la ON b.borrower_id = la.borrower_id;

SELECT loan_amount_disbursed
FROM loan_agreements
ORDER BY loan_amount_disbursed DESC;

SELECT SUM(lo.outstanding_amount) AS total_outstanding
FROM loans lo
WHERE lo.lender_id = 'specific_lender_id';
